      "hover:bg-stone-100 text-stone-600",
  };

  const sizes = {
    sm: "px-5 py-2.5 text-xs",
    md: "px-6 py-4 text-base",
    lg: "px-10 py-5 text-lg",
  };

  return (
    <button
      disabled={disabled || isLoading}
