"use client";

import React, { useState, useMemo } from "react";
import Link from "next/link";
import { Input } from "../ui/input";
import { Button } from "../ui/button";

export const SignUpForm: React.FC = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [errors, setErrors] = useState<{
    name?: string;
    email?: string;
    password?: string;
    confirmPassword?: string;
  }>({});
  const [isLoading, setIsLoading] = useState(false);
  const [authSuccess, setAuthSuccess] = useState(false);

  // Real-time password strength validation rules
  const passwordStrength = useMemo(() => {
    const checks = {
      length: password.length >= 8,
      uppercase: /[A-Z]/.test(password),
      numberOrSymbol: /[0-9!@#$%^&*(),.?":{}|<>]/.test(password),
    };

    const score = Object.values(checks).filter(Boolean).length;

    let label = "Empty";
    let colorClass = "text-zinc-400 dark:text-zinc-500";
    let barColor = "bg-zinc-200 dark:bg-zinc-800";

    if (password.length > 0) {
      if (score === 1) {
        label = "Weak";
        colorClass = "text-red-500 font-semibold";
        barColor = "bg-red-500";
      } else if (score === 2) {
        label = "Fair";
        colorClass = "text-amber-500 font-semibold";
        barColor = "bg-amber-500";
      } else if (score === 3) {
        label = "Strong";
        colorClass = "text-emerald-500 font-semibold";
        barColor = "bg-emerald-500";
      }
    }

    return { checks, score, label, colorClass, barColor };
  }, [password]);

  // Real-time password matching status
  const passwordsMatch = useMemo(() => {
    if (!confirmPassword) return null;
    return password === confirmPassword;
  }, [password, confirmPassword]);

  const validate = () => {
    const newErrors: typeof errors = {};
    if (!name.trim()) {
      newErrors.name = "Full name is required";
    }

    if (!email) {
      newErrors.email = "Email is required";
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      newErrors.email = "Please enter a valid email address";
    }

    if (!password) {
      newErrors.password = "Password is required";
    } else if (password.length < 8) {
      newErrors.password = "Password must be at least 8 characters";
    }

    if (password !== confirmPassword) {
      newErrors.confirmPassword = "Passwords do not match";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);
    // Simulate API request
    try {
      await new Promise((resolve) => setTimeout(resolve, 1500));
      setAuthSuccess(true);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (authSuccess) {
    return (
      <div className="flex flex-col items-center justify-center py-6 text-center animate-in fade-in zoom-in duration-500">
        <div className="flex h-16 w-16 items-center justify-center rounded-full bg-emerald-100/50 text-emerald-600 dark:bg-emerald-950/30 dark:text-emerald-400 mb-6 ring-8 ring-emerald-50 dark:ring-emerald-900/20">
          <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth={2.5}
            stroke="currentColor"
            className="h-8 w-8 animate-[bounce_1s_ease-in-out_2]"
          >
            <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
          </svg>
        </div>
        <h3 className="text-xl font-semibold text-zinc-950 dark:text-zinc-50">
          Account Created!
        </h3>
        <p className="mt-2 text-sm text-zinc-500 dark:text-zinc-400">
          Your account was successfully created. Proceeding to sign in page...
        </p>
        <Link href="/signin" className="mt-6 w-full">
          <Button variant="primary" className="w-full">Go to Sign In</Button>
        </Link>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-8 w-full animate-in fade-in slide-in-from-bottom-4 duration-500">
      <form onSubmit={handleSubmit} className="flex flex-col gap-5">
        <Input
          label="Full Name"
          id="name"
          type="text"
          placeholder="e.g. John Doe"
          value={name}
          onChange={(e) => {
            setName(e.target.value);
            if (errors.name) setErrors((prev) => ({ ...prev, name: undefined }));
          }}
          error={errors.name}
          required
        />

        <Input
          label="Email Address"
          id="email"
          type="email"
          placeholder="e.g. john@example.com"
          value={email}
          onChange={(e) => {
            setEmail(e.target.value);
            if (errors.email) setErrors((prev) => ({ ...prev, email: undefined }));
          }}
          error={errors.email}
          required
        />

        <Input
          label="Password"
          id="password"
          type={showPassword ? "text" : "password"}
          placeholder="••••••••"
          value={password}
          onChange={(e) => {
            setPassword(e.target.value);
            if (errors.password) setErrors((prev) => ({ ...prev, password: undefined }));
          }}
          error={errors.password}
          rightElement={
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="text-stone-400 hover:text-stone-900 transition-colors"
            >
              {showPassword ? "Hide" : "Show"}
            </button>
          }
          required
        />

        <Input
          label="Confirm Password"
          id="confirmPassword"
          type={showConfirmPassword ? "text" : "password"}
          placeholder="••••••••"
          value={confirmPassword}
          onChange={(e) => {
            setConfirmPassword(e.target.value);
            if (errors.confirmPassword)
              setErrors((prev) => ({ ...prev, confirmPassword: undefined }));
          }}
          error={errors.confirmPassword}
          rightElement={
            <button
              type="button"
              onClick={() => setShowConfirmPassword(!showConfirmPassword)}
              className="text-stone-400 hover:text-stone-900 transition-colors"
            >
              {showConfirmPassword ? "Hide" : "Show"}
            </button>
          }
          required
        />

        <Button 
          type="submit" 
          variant="primary" 
          className="w-full mt-2 h-14 text-lg font-black bg-stone-900 text-white rounded-2xl hover:bg-stone-800 transition-all shadow-lg active:scale-[0.98]" 
          isLoading={isLoading}
        >
          Create account
        </Button>

        <p className="mt-2 text-center text-sm font-medium text-stone-500">
          Already have an account?{" "}
          <Link
            href="/signin"
            className="font-bold text-stone-900 underline underline-offset-4 decoration-stone-200 hover:decoration-stone-900 transition-all"
          >
            Sign in
          </Link>
        </p>
      </form>
    </div>
  );
};

