"use client";

import React, { useState } from "react";
import Link from "next/link";
import { Input } from "../ui/input";
import { Button } from "../ui/button";

export const SignInForm: React.FC = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [errors, setErrors] = useState<{ email?: string; password?: string }>({});
  const [isLoading, setIsLoading] = useState(false);
  const [authSuccess, setAuthSuccess] = useState(false);

  const validate = () => {
    const newErrors: { email?: string; password?: string } = {};
    if (!email) {
      newErrors.email = "Email is required";
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      newErrors.email = "Please enter a valid email address";
    }

    if (!password) {
      newErrors.password = "Password is required";
    } else if (password.length < 6) {
      newErrors.password = "Password must be at least 6 characters";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);
    // Simulate API request
    try {
      await new Promise((resolve) => setTimeout(resolve, 1500));
      setAuthSuccess(true);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (authSuccess) {
    return (
      <div className="flex flex-col items-center justify-center py-6 text-center animate-in fade-in zoom-in duration-500">
        <div className="flex h-16 w-16 items-center justify-center rounded-full bg-emerald-100/50 text-emerald-600 dark:bg-emerald-950/30 dark:text-emerald-400 mb-6 ring-8 ring-emerald-50 dark:ring-emerald-900/20">
          <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth={2.5}
            stroke="currentColor"
            className="h-8 w-8 animate-[bounce_1s_ease-in-out_2]"
          >
            <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
          </svg>
        </div>
        <h3 className="text-xl font-semibold text-zinc-950 dark:text-zinc-50">
          Welcome back!
        </h3>
        <p className="mt-2 text-sm text-zinc-500 dark:text-zinc-400 max-w-[80%] mx-auto">
          We&apos;re securely authenticating you and loading your workspace...
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-8 w-full animate-in fade-in slide-in-from-bottom-4 duration-500">
      <form onSubmit={handleSubmit} className="flex flex-col gap-6">
        <Input
          label="Email Address"
          id="email"
          type="email"
          placeholder="e.g. john@example.com"
          value={email}
          onChange={(e) => {
            setEmail(e.target.value);
            if (errors.email) setErrors((prev) => ({ ...prev, email: undefined }));
          }}
          error={errors.email}
          required
        />

        <div className="flex flex-col gap-1.5">
          <div className="flex items-center justify-between">
            <label
              htmlFor="password"
              className="text-sm font-bold text-stone-900"
            >
              Password
            </label>
            <a
              href="#"
              className="text-xs font-bold text-stone-400 hover:text-stone-900 transition-colors"
            >
              Forgot?
            </a>
          </div>
          <Input
            id="password"
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => {
              setPassword(e.target.value);
              if (errors.password) setErrors((prev) => ({ ...prev, password: undefined }));
            }}
            error={errors.password}
            required
          />
        </div>

        <Button 
          type="submit" 
          variant="primary" 
          className="w-full mt-2 h-14 text-lg font-black bg-stone-900 text-white rounded-2xl hover:bg-stone-800 transition-all shadow-lg active:scale-[0.98]" 
          isLoading={isLoading}
        >
          Sign in
        </Button>

        <p className="mt-4 text-center text-sm font-medium text-stone-500">
          Don&apos;t have an account?{" "}
          <Link
            href="/signup"
            className="font-bold text-stone-900 underline underline-offset-4 decoration-stone-200 hover:decoration-stone-900 transition-all"
          >
            Sign up
          </Link>
        </p>
      </form>
    </div>
  );
};

