import React, { useState } from "react";
import Link from "next/link";
import { Input } from "../ui/input";
import { Button } from "../ui/button";

export const SignInForm: React.FC = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [errors, setErrors] = useState<{ email?: string; password?: string }>({});
  const [isLoading, setIsLoading] = useState(false);
  const [authSuccess, setAuthSuccess] = useState(false);

  const validate = () => {
    const newErrors: { email?: string; password?: string } = {};
    if (!email) newErrors.email = "Required";
    if (!password) newErrors.password = "Required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsLoading(true);
    await new Promise((resolve) => setTimeout(resolve, 1000));
    setAuthSuccess(true);
    setIsLoading(false);
  };

  if (authSuccess) {
    return (
      <div className="flex flex-col items-center py-4 text-center animate-in fade-in zoom-in duration-500">
        <h3 className="text-2xl font-black text-stone-900">Signed In</h3>
        <p className="mt-2 text-sm font-medium text-stone-500">Loading your space...</p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-6 w-full">
      <Input
        label="Email"
        id="email"
        type="email"
        placeholder="you@email.com"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        error={errors.email}
      />

      <div className="flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <label htmlFor="password" className="text-sm font-black text-stone-900">
            Password
          </label>
          <a href="#" className="text-xs font-bold text-stone-400">Forgot?</a>
        </div>
        <Input
          id="password"
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          error={errors.password}
        />
      </div>

      <Button type="submit" className="h-16 mt-2 text-xl" isLoading={isLoading}>
        SIGN IN
      </Button>

      <p className="mt-4 text-center text-xs font-bold text-stone-400 uppercase tracking-widest">
        New here?{" "}
        <Link href="/signup" className="text-stone-900 underline decoration-2 underline-offset-4">
          CREATE ACCOUNT
        </Link>
      </p>
    </form>
  );
};
};

