"use client";

import React from "react";

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: "primary" | "secondary" | "outline" | "ghost";
  size?: "sm" | "md" | "lg";
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({
  children,
  variant = "primary",
  size = "md",
  isLoading = false,
  className = "",
  disabled,
  ...props
}) => {
  const baseStyles =
    "relative inline-flex items-center justify-center rounded-2xl font-black tracking-tight transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer active:scale-[0.98] overflow-hidden";

  const variants = {
    primary:
      "bg-stone-900 text-stone-50 hover:bg-stone-800 shadow-[0_12px_24px_-8px_rgba(0,0,0,0.2)] hover:shadow-[0_16px_32px_-8px_rgba(0,0,0,0.3)]",
    secondary:
      "bg-stone-100 text-stone-900 hover:bg-stone-200",
    outline:
      "border-2 border-stone-200 hover:border-stone-900 hover:bg-stone-50 text-stone-900",
    ghost:
      "hover:bg-stone-100 text-stone-600",
  };

  const sizes = {
    sm: "px-5 py-2.5 text-xs",
    md: "px-6 py-4 text-base",
    lg: "px-10 py-5 text-lg",
  };

  return (
    <button
      disabled={disabled || isLoading}
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {isLoading ? (
        <svg
          className="animate-spin -ml-1 mr-2 h-5 w-5 text-current"
          fill="none"
          viewBox="0 0 24 24"
        >
          <circle
            className="opacity-25"
            cx="12"
            cy="12"
            r="10"
            stroke="currentColor"
            strokeWidth="4"
          />
          <path
            className="opacity-75"
            fill="currentColor"
            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
          />
        </svg>
      ) : null}
      <span className="flex items-center gap-2">{children}</span>
    </button>
  );
};

