"use client";

import React, { useState } from "react";
import Link from "next/link";
import { Input } from "../ui/input";
import { Button } from "../ui/button";

export const SignUpForm: React.FC = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [errors, setErrors] = useState<{
    name?: string;
    email?: string;
    password?: string;
  }>({});
  const [isLoading, setIsLoading] = useState(false);
  const [authSuccess, setAuthSuccess] = useState(false);

  const validate = () => {
    const newErrors: typeof errors = {};
    if (!name.trim()) newErrors.name = "Name is required";
    if (!email) newErrors.email = "Email is required";
    if (!password) newErrors.password = "Password is required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsLoading(true);
    await new Promise((resolve) => setTimeout(resolve, 1000));
    setAuthSuccess(true);
    setIsLoading(false);
  };

  if (authSuccess) {
    return (
      <div className="flex flex-col items-center py-4 text-center animate-in fade-in zoom-in duration-500">
        <h3 className="text-2xl font-black text-stone-900">Welcome!</h3>
        <p className="mt-2 text-sm font-medium text-stone-500">Account ready. Redirecting...</p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-4 w-full">
      <Input
        label="Name"
        id="name"
        placeholder="John"
        value={name}
        onChange={(e) => setName(e.target.value)}
        error={errors.name}
      />
      <Input
        label="Email"
        id="email"
        type="email"
        placeholder="john@email.com"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        error={errors.email}
      />
      <Input
        label="Password"
        id="password"
        type={showPassword ? "text" : "password"}
        placeholder="••••••••"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        error={errors.password}
        rightElement={
          <button type="button" onClick={() => setShowPassword(!showPassword)} className="font-black">
            {showPassword ? "HIDE" : "SHOW"}
          </button>
        }
      />

      <Button type="submit" className="h-16 mt-2 text-xl" isLoading={isLoading}>
        SIGN UP
      </Button>

      <p className="mt-4 text-center text-xs font-bold text-stone-400 uppercase tracking-widest">
        Have an account?{" "}
        <Link href="/signin" className="text-stone-900 underline decoration-2 underline-offset-4">
          LOG IN
        </Link>
      </p>
    </form>
  );
};

